from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """Generate a natural language sentence from a list of triples."""
    if not triples:
        return ""

    def clean_subject(subject: str) -> str:
        """Remove '(comicsCharacter)' suffix from subject names."""
        return subject.replace(" (comicsCharacter)", "").replace("(comicsCharacter)", "")

    def clean_object(obj: str) -> str:
        """Remove surrounding quotes from object values."""
        if obj and ((obj.startswith('"') and obj.endswith('"')) or (obj.startswith("'") and obj.endswith("'"))):
            return obj[1:-1]
        return obj

    # Group triples by subject for complex sentence building
    subject_triples = {}
    for t in triples:
        subject = clean_subject(t.subject)
        if subject not in subject_triples:
            subject_triples[subject] = []
        subject_triples[subject].append((t.predicate, clean_object(t.object)))

    # Mapping predicates to phrase generators with better grammar
    def alt_name(s, o): return f"also known as {o}"
    def creator(s, o): return f"was created by {o}"
    def full_name(s, o): return f"whose full name is {o}"
    def founded_by(s, o): return f"was founded by {o}"
    def key_person(s, o): return f"with {o} as a key person"
    def city(s, o): return f"located in {o}"
    def product(s, o): return f"produces {o}"
    def last_aired(s, o): return f"last aired on {o}"
    def starring(s, o): return f"stars {o}"
    def first_appearance(s, o): return f"first appeared in the film {o}"
    def voice(s, o): return f"voiced by {o}"
    def distributor(s, o): return f"distributed by {o}"
    def birth_place(s, o): return f"was born in {o}"
    def nationality(s, o):
        # Handle nationality more naturally
        o_lower = o.lower()
        if o_lower == "americans" or o_lower == "united states" or o_lower == "usa":
            return "American"
        elif o_lower == "canadians" or o_lower == "canada":
            return "Canadian"
        elif o_lower == "british" or o_lower == "united kingdom" or o_lower == "uk":
            return "British"
        elif o_lower.endswith("s") and o_lower not in ["us", "uk"]:
            return o[:-1]
        else:
            return o
    def award(s, o): return f"received the {o}"
    def broadcasted_by(s, o): return f"was broadcasted by {o}"
    def first_aired(s, o): return f"first aired on {o}"
    def series(s, o): return f"part of the series {o}"
    def child(s, o): return f"has a child named {o}"

    phrase_funcs = {
        "alternativeName": alt_name,
        "creator": creator,
        "fullName": full_name,
        "foundedBy": founded_by,
        "keyPerson": key_person,
        "city": city,
        "product": product,
        "lastAired": last_aired,
        "starring": starring,
        "firstAppearanceInFilm": first_appearance,
        "voice": voice,
        "distributor": distributor,
        "birthPlace": birth_place,
        "nationality": nationality,
        "award": award,
        "broadcastedBy": broadcasted_by,
        "firstAired": first_aired,
        "series": series,
        "child": child,
    }

    # Build complex sentence from all triples
    all_clauses = []
    seen_predicates = {}

    for subject, subject_trips in subject_triples.items():
        # Sort triples by priority (more important info first)
        priority = ["creator", "fullName", "alternativeName", "nationality", "birthPlace", "award", "child"]
        sorted_trips = sorted(subject_trips, key=lambda t: priority.index(t[0]) if t[0] in priority else len(priority))

        # Group by predicate to handle multiple values for same predicate (e.g., multiple creators)
        predicate_objects = {}
        for pred, obj in sorted_trips:
            if pred not in predicate_objects:
                predicate_objects[pred] = []
            predicate_objects[pred].append(obj)

        # Convert back to unique_trips with combined objects
        unique_trips = []
        for pred in sorted(predicate_objects.keys(), key=lambda p: priority.index(p) if p in priority else len(priority)):
            if len(predicate_objects[pred]) > 1:
                # Join multiple objects with "and"
                combined_obj = " and ".join(predicate_objects[pred])
                unique_trips.append((pred, combined_obj))
            else:
                unique_trips.append((pred, predicate_objects[pred][0]))

        if len(unique_trips) == 1:
            pred, obj = unique_trips[0]
            func = phrase_funcs.get(pred)
            if func:
                if pred == "nationality":
                    all_clauses.append(f"{subject} is {func(subject, obj)}")
                else:
                    all_clauses.append(f"{subject} {func(subject, obj)}")
            else:
                all_clauses.append(f"{subject} {pred} {obj}")
        else:
            # Multiple triples for same subject - build complex sentence
            main_clause = f"{subject}"
            clauses = []

            for i, (pred, obj) in enumerate(unique_trips):
                func = phrase_funcs.get(pred)
                if func:
                    if i == 0:
                        # First predicate becomes main verb
                        if pred == "nationality":
                            clauses.append(f" is {func(subject, obj)}")
                        else:
                            clauses.append(f" {func(subject, obj)}")
                    else:
                        # Subsequent predicates become relative clauses
                        clauses.append(f", {func(subject, obj)}")

            all_clauses.append(main_clause + "".join(clauses))

    # Combine all subject sentences into one complex sentence
    # Clean up any double spaces
    def clean_spaces(text):
        while "  " in text:
            text = text.replace("  ", " ")
        return text.strip()

    if len(all_clauses) == 0:
        return ""

    if len(all_clauses) == 1:
        result = clean_spaces(all_clauses[0])
        if not result.endswith("."):
            result += "."
        return result
    else:
        # Connect all subjects into ONE complex sentence using relative clauses
        result = all_clauses[0]
        for i, part in enumerate(all_clauses[1:]):
            # Extract subject from the part to create relative clause
            if " is " in part or " was " in part:
                result += f", which is related to {part}"
            else:
                result += f", and {part}"
        result = clean_spaces(result)
        if not result.endswith("."):
            result += "."
        return result

